// 資料正規化
const items = $input.all();
const normalized = [];

for (const item of items) {
  const data = item.json;

  const normalizedItem = {
    title: data.title || data.name || '',
    description: data.description || data.content || data.summary || '',
    url: data.link || data.url || '',
    publishDate: data.pubDate || data.date || data.publishedAt || new Date().toISOString(),
    source: data.source || 'Unknown',
    image: data.image || data.thumbnail || '',
    rawData: data,
    processedAt: new Date().toISOString()
  };

  normalizedItem.title = normalizedItem.title.trim();
  normalizedItem.description = normalizedItem.description.trim();

  if (normalizedItem.title && normalizedItem.description) {
    normalized.push({ json: normalizedItem });
  }
}

return normalized;

// 關鍵字過濾
const items = $input.all();
const filtered = [];

const STEAM_KEYWORDS = [
  '科學', '物理', '化學', '生物', '地球科學', '環境',
  '程式', '編程', '資訊', 'AI', '人工智慧', '機器學習', '程式設計',
  '工程', '機器人', '創客', 'Maker', '電子', '機械',
  '藝術', '設計', '創意', '美術', '音樂',
  '數學', '統計', '邏輯',
  'STEAM', 'STEM', '競賽', '比賽', '挑戰賽'
];

for (const item of items) {
  const data = item.json;
  const text = (data.title + ' ' + data.description).toLowerCase();

  const matchedKeywords = STEAM_KEYWORDS.filter(keyword => 
    text.includes(keyword.toLowerCase())
  );

  if (matchedKeywords.length > 0) {
    filtered.push({
      json: {
        ...data,
        matchedKeywords,
        relevanceScore: matchedKeywords.length / STEAM_KEYWORDS.length
      }
    });
  }
}

return filtered;

// 五層去重機制
const crypto = require('crypto');

function md5(data) {
  return crypto.createHash('md5').update(JSON.stringify(data)).digest('hex');
}

function similarity(s1, s2) {
  const m = Math.max(s1.length, s2.length);
  if (!m) return 1;
  const d = [];
  for (let i = 0; i <= s1.length; i++) {
    d[i] = [i];
    for (let j = 1; j <= s2.length; j++) {
      d[i][j] = i === 0 ? j : 0;
    }
  }
  for (let i = 1; i <= s1.length; i++) {
    for (let j = 1; j <= s2.length; j++) {
      d[i][j] = Math.min(
        d[i-1][j] + 1,
        d[i][j-1] + 1,
        d[i-1][j-1] + (s1[i-1] === s2[j-1] ? 0 : 1)
      );
    }
  }
  return 1 - d[s1.length][s2.length] / m;
}

function tfidf(text, corpus) {
  const words = text.toLowerCase().match(/[\u4e00-\u9fa5a-z0-9]+/g) || [];
  const freq = {};
  words.forEach(w => { freq[w] = (freq[w] || 0) + 1; });
  const result = {};
  for (const w of Object.keys(freq)) {
    const df = corpus.filter(d => d.toLowerCase().includes(w)).length;
    result[w] = freq[w] * Math.log((corpus.length + 1) / (df + 1));
  }
  return result;
}

function cosine(v1, v2) {
  const keys = new Set([...Object.keys(v1), ...Object.keys(v2)]);
  let dot = 0, m1 = 0, m2 = 0;
  for (const k of keys) {
    const a = v1[k] || 0, b = v2[k] || 0;
    dot += a * b; m1 += a * a; m2 += b * b;
  }
  return (!m1 || !m2) ? 0 : dot / (Math.sqrt(m1) * Math.sqrt(m2));
}

const TITLE_THRESHOLD = 0.85;
const CONTENT_THRESHOLD = 0.90;
const TIME_WINDOW_MS = 7 * 24 * 60 * 60 * 1000;

// 從讀取現有資料節點取得已存在的資料
const existingItems = $input.all().map(e => e.json);
// 從關鍵字過濾節點取得新資料
const newItems = $('關鍵字過濾').all();

const results = [];
const corpus = existingItems.map(i => i.description || '');

for (const item of newItems) {
  const d = item.json;
  let isDup = false;

  // Layer 1: Hash
  const h = md5({ title: d.title, url: d.url, description: d.description });
  if (existingItems.some(e => md5({ title: e.title, url: e.url, description: e.description }) === h)) {
    isDup = true;
  }

  // Layer 2: URL
  if (!isDup && d.url && existingItems.some(e => e.url === d.url)) {
    isDup = true;
  }

  // Layer 3: Title similarity
  if (!isDup && existingItems.some(e => similarity(d.title || '', e.title || '') >= TITLE_THRESHOLD)) {
    isDup = true;
  }

  // Layer 4: Time window + title
  if (!isDup) {
    const ts = new Date(d.publishDate || Date.now()).getTime();
    isDup = existingItems.some(e => {
      const ets = new Date(e.publishDate || e.scraped_at || Date.now()).getTime();
      return Math.abs(ts - ets) <= TIME_WINDOW_MS && similarity(d.title || '', e.title || '') >= 0.70;
    });
  }

  // Layer 5: Content TF-IDF + Cosine
  if (!isDup) {
    const allCorpus = [...corpus, d.description || ''];
    const v1 = tfidf(d.description || '', allCorpus);
    isDup = existingItems.some(e => cosine(v1, tfidf(e.description || '', allCorpus)) >= CONTENT_THRESHOLD);
  }

  if (!isDup) {
    results.push({ json: { ...d, processedAt: new Date().toISOString() } });
  }
}

console.log('去重結果: ' + newItems.length + ' 筆輸入, ' + results.length + ' 筆通過');
return results;

// 整合 AI 分類結果與原始資料
const crypto = require('crypto');
const items = $input.all();
const originalItems = $('五層去重').all();
const categoryMap = { S: 'Science', T: 'Technology', E: 'Engineering', A: 'Arts', M: 'Mathematics' };
const results = [];

for (let i = 0; i < originalItems.length; i++) {
  const original = originalItems[i]?.json || {};
  const apiResponse = items[i]?.json || {};
  let aiResult = {};

  try {
    const content = apiResponse.choices?.[0]?.message?.content || '{}';
    aiResult = JSON.parse(content);
  } catch (e) {
    aiResult = {
      categories: ['Mixed'],
      primary: 'T',
      confidence: 0.5,
      summary: (original.description || '').substring(0, 150),
      keyPoints: [],
      reasoning: 'AI parsing failed'
    };
  }

  const id = 'steam_' + new Date().getFullYear() + '_' + crypto.randomBytes(4).toString('hex');
  const hashKey = crypto.createHash('md5')
    .update(JSON.stringify({ title: original.title, url: original.url }))
    .digest('hex');

  results.push({
    json: {
      id,
      title: original.title || '',
      organizer: original.source || '',
      category: categoryMap[aiResult.primary] || 'Mixed',
      target_audience: '全年齡',
      registration_start: '',
      registration_end: '',
      competition_date: '',
      location: '',
      description: original.description || '',
      url: original.url || '',
      contact: '',
      prize: '',
      fee: '',
      source: original.source || '',
      scraped_at: new Date().toISOString(),
      status: 'active',
      hash_key: hashKey,
      sent_to_line: 'FALSE',
      sent_at: '',
      classification: {
        categories: aiResult.categories || ['Mixed'],
        primary: aiResult.primary || 'T',
        confidence: aiResult.confidence || 0.5,
        reasoning: aiResult.reasoning || ''
      },
      summary: {
        summary: aiResult.summary || (original.description || '').substring(0, 150),
        keyPoints: aiResult.keyPoints || [],
        callToAction: aiResult.callToAction || ''
      },
      publishDate: original.publishDate || '',
      matchedKeywords: original.matchedKeywords || [],
      relevanceScore: original.relevanceScore || 0,
      image: original.image || ''
    }
  });
}

return results;

// LINE Flex Message 格式化
const COLORS = {
  S: { p: '#4CAF50', s: '#81C784', n: '科學' },
  T: { p: '#2196F3', s: '#64B5F6', n: '技術' },
  E: { p: '#FF9800', s: '#FFB74D', n: '工程' },
  A: { p: '#E91E63', s: '#F06292', n: '藝術' },
  M: { p: '#9C27B0', s: '#BA68C8', n: '數學' }
};

function fmtDate(d) {
  if (!d) return '日期未定';
  const dt = new Date(d);
  return dt.getFullYear() + '/' + String(dt.getMonth() + 1).padStart(2, '0') + '/' + String(dt.getDate()).padStart(2, '0');
}

function createBubble(c) {
  const pc = c.classification?.primary || 'T';
  const cats = c.classification?.categories || [pc];
  const sum = c.summary?.summary || (c.description || '').substring(0, 150);
  const kp = c.summary?.keyPoints || [];

  const badges = cats.map(cat => ({
    type: 'box', layout: 'baseline',
    backgroundColor: (COLORS[cat] || { p: '#999999' }).p,
    cornerRadius: 'md', paddingAll: 'sm', margin: 'xs',
    contents: [{ type: 'text', text: (COLORS[cat] || { n: cat }).n, color: '#ffffff', size: 'xs', weight: 'bold', flex: 0 }]
  }));

  const footerContents = [];
  if (kp.length > 0) {
    footerContents.push({
      type: 'box', layout: 'vertical', spacing: 'xs',
      contents: kp.map(p => ({ type: 'text', text: '• ' + p, size: 'xs', color: '#666666', wrap: true }))
    });
    footerContents.push({ type: 'separator', margin: 'md' });
  }
  footerContents.push({
    type: 'button', style: 'primary', height: 'sm',
    color: (COLORS[pc] || { p: '#2196F3' }).p,
    action: { type: 'uri', label: '查看詳情', uri: c.url || 'https://example.com' }
  });
  footerContents.push({
    type: 'button', style: 'link', height: 'sm',
    action: { type: 'uri', label: '分享給朋友', uri: 'https://line.me/R/msg/text/?' + encodeURIComponent((c.title || '') + ' ' + (c.url || '')) }
  });

  return {
    type: 'bubble', size: 'mega',
    header: {
      type: 'box', layout: 'vertical',
      backgroundColor: (COLORS[pc] || { s: '#f0f0f0' }).s,
      paddingAll: 'md',
      contents: [{ type: 'box', layout: 'horizontal', contents: badges }]
    },
    body: {
      type: 'box', layout: 'vertical',
      contents: [
        { type: 'text', text: c.title || '未命名比賽', weight: 'bold', size: 'xl', wrap: true },
        { type: 'box', layout: 'vertical', margin: 'lg', spacing: 'sm', contents: [
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '📅', size: 'sm', flex: 0 },
            { type: 'text', text: fmtDate(c.publishDate), color: '#666666', size: 'sm', flex: 5, wrap: true }
          ]},
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '🏢', size: 'sm', flex: 0 },
            { type: 'text', text: c.organizer || c.source || '未知', color: '#666666', size: 'sm', flex: 5, wrap: true }
          ]}
        ]},
        { type: 'separator', margin: 'lg' },
        { type: 'text', text: sum, wrap: true, color: '#333333', size: 'sm', margin: 'lg' }
      ]
    },
    footer: { type: 'box', layout: 'vertical', spacing: 'sm', flex: 0, contents: footerContents }
  };
}

const items = $input.all();
const competitions = items.map(i => i.json);

let flexContents;
if (competitions.length > 1) {
  flexContents = { type: 'carousel', contents: competitions.slice(0, 10).map(createBubble) };
} else if (competitions.length === 1) {
  flexContents = createBubble(competitions[0]);
} else {
  return [];
}

return items.map(item => ({
  json: {
    ...item.json,
    lineMessage: {
      to: 'YOUR_LINE_GROUP_ID',
      messages: [{
        type: 'flex',
        altText: '發現 ' + items.length + ' 個新的 STEAM 比賽資訊',
        contents: flexContents
      }]
    }
  }
}));

// 更新監控數據
const now = new Date();
const dateStr = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + String(now.getDate()).padStart(2, '0');

let dataCollected = 0;
let newData = 0;
let filtered = 0;

try { filtered = $('關鍵字過濾').all().length; } catch (e) {}
try { dataCollected = $('資料正規化').all().length; } catch (e) {}
try { newData = $input.all().length; } catch (e) {}

const dedupRate = filtered > 0 ? ((filtered - newData) / filtered * 100).toFixed(1) + '%' : '0%';
const qualityScore = dataCollected > 0 ? (filtered / dataCollected * 100).toFixed(1) + '%' : '0%';

return [{
  json: {
    date: dateStr,
    execution_count: 1,
    success_count: newData > 0 ? 1 : 0,
    failure_count: 0,
    success_rate: newData > 0 ? '100%' : '0%',
    data_collected: dataCollected,
    new_data: newData,
    dedup_rate: dedupRate,
    line_sent: newData,
    line_success_rate: newData > 0 ? '100%' : 'N/A',
    avg_execution_time: 0,
    error_count: 0,
    data_quality_score: qualityScore
  }
}];

// LINE 純文字備用格式（Flex Message 失敗時的降級方案）
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const text = [
    '\ud83c\udfc6 STEAM 比賽資訊',
    '━━━━━━━━━━━━',
    '\ud83d\udccc ' + (d.title || '未命名'),
    '\ud83c\udfe2 ' + (d.organizer || d.source || '未知'),
    '\ud83d\udcc5 截止：' + (d.registration_end || '未定'),
    '\ud83c\udfaf 對象：' + (d.target_audience || '全年齡'),
    '\ud83d\udd17 ' + (d.url || ''),
    '━━━━━━━━━━━━'
  ].join('\n');

  results.push({
    json: {
      ...d,
      lineMessage: {
        to: 'YOUR_LINE_GROUP_ID',
        messages: [{ type: 'text', text: text }]
      }
    }
  });
}

return results;
